#!/usr/bin/env python3
from pathlib import Path
import base64
import re
import shutil
import subprocess
import tempfile

MAIN = Path("lib/main.dart")
PUBSPEC = Path("pubspec.yaml")
TARGET = Path("lib/visual_collection.dart")

VISUAL_B64 = """"""

def run(command):
    print("$ " + " ".join(command))
    return subprocess.run(command, check=True)

for path in [MAIN, PUBSPEC]:
    if not path.exists():
        raise SystemExit(
            f"Gerekli dosya bulunamadı: {path}\n"
            "Kurulumu BilgiRotasi deposunun ana klasöründe çalıştır."
        )

branch = subprocess.check_output(
    ["git", "branch", "--show-current"],
    text=True,
).strip()

if branch != "main":
    raise SystemExit(
        "Bu geliştirme yalnızca main dalına kurulabilir.\n"
        f"Şu anki dal: {branch or '(belirsiz)'}\n"
        "Önce: git switch main"
    )

main = MAIN.read_text(encoding="utf-8")
pubspec = PUBSPEC.read_text(encoding="utf-8")

if "part 'visual_collection.dart';" in main or TARGET.exists():
    raise SystemExit(
        "Koleksiyon ve görünüm sistemi zaten kurulmuş görünüyor."
    )

required = [
    "part 'retention_system.dart';",
    "class SoundFx",
    "static Future<bool> _play(",
    "await RetentionProgressService.initialize();",
    "const RetentionHomeCard(),",
    "class BoardPainter extends CustomPainter",
    "const BoardPainter();",
    "painter: BoardPainter(),",
    "int _pawnType = 0;",
]

for marker in required:
    if marker not in main:
        raise SystemExit(
            f"Beklenen main.dart bölümü bulunamadı: {marker}"
        )

version_match = re.search(
    r"^version:\s*(\d+)\.(\d+)\.(\d+)\+(\d+)\s*$",
    pubspec,
    flags=re.MULTILINE,
)

if version_match is None:
    raise SystemExit("pubspec.yaml sürüm satırı okunamadı.")

major, minor, patch, build = map(
    int,
    version_match.groups(),
)

if (major, minor) != (1, 25):
    raise SystemExit(
        "Bu paket 1.25.x sürümü için hazırlandı.\n"
        f"Depodaki sürüm: {major}.{minor}.{patch}+{build}"
    )

new_version = f"1.26.0+{build + 1}"

backup_dir = Path(tempfile.mkdtemp(
    prefix="bilgi_rotasi_visual_collection_"
))
committed = False

try:
    shutil.copy2(MAIN, backup_dir / "main.dart")
    shutil.copy2(PUBSPEC, backup_dir / "pubspec.yaml")

    TARGET.write_text(
        base64.b64decode(VISUAL_B64).decode("utf-8"),
        encoding="utf-8",
    )

    main = main.replace(
        "part 'retention_system.dart';",
        "part 'retention_system.dart';\n"
        "part 'visual_collection.dart';",
        1,
    )

    init_marker = """  try {
    await RetentionProgressService.initialize();
  } catch (_) {
    // Günlük ve haftalık sistem açılamasa bile oyun devam eder.
  }

  runApp(const BilgiRotasiApp());"""

    if init_marker not in main:
        raise RuntimeError(
            "Koleksiyon başlangıç noktası bulunamadı."
        )

    main = main.replace(
        init_marker,
        """  try {
    await RetentionProgressService.initialize();
  } catch (_) {
    // Günlük ve haftalık sistem açılamasa bile oyun devam eder.
  }

  try {
    await VisualCollectionService.initialize();
  } catch (_) {
    // Koleksiyon sistemi açılamasa bile oyun devam eder.
  }

  runApp(const BilgiRotasiApp());""",
        1,
    )

    sound_marker = """      await player.play(
        DeviceFileSource(path),
        volume: volume.clamp(0.0, 1.0).toDouble(),
      );"""

    if sound_marker not in main:
        raise RuntimeError(
            "Ses atmosferi entegrasyon noktası bulunamadı."
        )

    main = main.replace(
        sound_marker,
        """      final atmosphere =
          VisualCollectionService.sound;

      await player.setPlaybackRate(
        atmosphere.playbackRate,
      );

      await player.play(
        DeviceFileSource(path),
        volume: (
          volume * atmosphere.volumeMultiplier
        ).clamp(0.0, 1.0).toDouble(),
      );""",
        1,
    )

    home_marker = """                const RetentionHomeCard(),
                const SizedBox(height: 16),
                _buildNewGameCard(),"""

    if home_marker not in main:
        raise RuntimeError(
            "Ana ekran koleksiyon düğmesi ekleme noktası bulunamadı."
        )

    main = main.replace(
        home_marker,
        """                const RetentionHomeCard(),
                const SizedBox(height: 10),
                const CollectionHomeButton(),
                const SizedBox(height: 16),
                _buildNewGameCard(),""",
        1,
    )

    solo_start = main.index(
        "class _SoloRouteSetupScreenState"
    )
    solo_end = main.index(
        "class MarathonSetupScreen",
        solo_start,
    )
    solo_block = main[solo_start:solo_end]

    if "int _pawnType = 0;" not in solo_block:
        raise RuntimeError(
            "Serbest Rota favori piyon noktası bulunamadı."
        )

    solo_block = solo_block.replace(
        "int _pawnType = 0;",
        "int _pawnType = "
        "VisualCollectionService.current.favoritePawn;",
        1,
    )

    main = (
        main[:solo_start]
        + solo_block
        + main[solo_end:]
    )

    board_layer_marker = """              const Positioned.fill(
                child: CustomPaint(
                  painter: BoardPainter(),
                ),
              ),"""

    if board_layer_marker not in main:
        raise RuntimeError(
            "Canlı tahta katmanı ekleme noktası bulunamadı."
        )

    main = main.replace(
        board_layer_marker,
        """              const Positioned.fill(
                child: LiveBoardLayer(),
              ),""",
        1,
    )

    painter_header = """class BoardPainter extends CustomPainter {
  const BoardPainter();

  static const _gold = Color(0xFFE8C76A);
  static const _darkGold = Color(0xFF7B5721);
  static const _deepPurple = Color(0xFF24122F);"""

    if painter_header not in main:
        raise RuntimeError(
            "Tahta tema başlığı beklenenden farklı."
        )

    main = main.replace(
        painter_header,
        """class BoardPainter extends CustomPainter {
  const BoardPainter({this.pulse = 0});

  final double pulse;

  BoardThemeDefinition get _theme =>
      VisualCollectionService.theme;

  Color get _gold => _theme.gold;
  Color get _darkGold => _theme.darkGold;
  Color get _deepPurple =>
      _theme.backgroundColors.last;""",
        1,
    )

    background_marker = """        ..shader = const LinearGradient(
          begin: Alignment.topLeft,
          end: Alignment.bottomRight,
          colors: [
            Color(0xFF56336B),
            Color(0xFF382047),
            Color(0xFF1D1027),
          ],
        ).createShader(boardRect),"""

    if background_marker not in main:
        raise RuntimeError(
            "Tahta arka plan renkleri bulunamadı."
        )

    main = main.replace(
        background_marker,
        """        ..shader = LinearGradient(
          begin: Alignment.topLeft,
          end: Alignment.bottomRight,
          colors: _theme.backgroundColors,
        ).createShader(boardRect),""",
        1,
    )

    main = main.replace(
        "..color = const Color(0xFF2B1837),",
        "..color = _theme.foundation,",
        1,
    )

    center_marker = """        ..shader = const RadialGradient(
          center: Alignment(-0.35, -0.38),
          colors: [
            Color(0xFF2B7184),
            Color(0xFF153E50),
            Color(0xFF071E2A),
          ],
        ).createShader(Rect.fromCircle(center: center, radius: radius)),"""

    if center_marker not in main:
        raise RuntimeError(
            "Tahta merkez tema renkleri bulunamadı."
        )

    main = main.replace(
        center_marker,
        """        ..shader = RadialGradient(
          center: const Alignment(-0.35, -0.38),
          colors: _theme.centerColors,
        ).createShader(
          Rect.fromCircle(
            center: center,
            radius: radius,
          ),
        ),""",
        1,
    )

    center_border = """        ..strokeWidth = 3.2
        ..color = const Color(0xFFFFD978),"""

    if center_border not in main:
        raise RuntimeError(
            "Tahta merkez çerçevesi bulunamadı."
        )

    main = main.replace(
        center_border,
        """        ..strokeWidth = 3.2
        ..color = _gold,""",
        1,
    )

    repaint_marker = """  @override
  bool shouldRepaint(covariant CustomPainter oldDelegate) => false;
}"""

    if repaint_marker not in main:
        raise RuntimeError(
            "Tahta yeniden çizim bölümü bulunamadı."
        )

    main = main.replace(
        repaint_marker,
        """  @override
  bool shouldRepaint(
    covariant BoardPainter oldDelegate,
  ) {
    return oldDelegate.pulse != pulse ||
        oldDelegate._theme.id != _theme.id;
  }
}""",
        1,
    )

    # Hafif canlı parlama: yalnızca tahta açıksa görünür.
    shadow_marker = """    canvas.drawShadow(
      Path()..addRRect(boardShape),
      const Color(0xAA000000),
      15,
      true,
    );"""

    if shadow_marker not in main:
        raise RuntimeError(
            "Canlı tahta parlama noktası bulunamadı."
        )

    main = main.replace(
        shadow_marker,
        """    canvas.drawShadow(
      Path()..addRRect(boardShape),
      const Color(0xAA000000),
      15,
      true,
    );

    if (pulse > 0) {
      canvas.drawRRect(
        boardShape.inflate(2 + pulse * 3),
        Paint()
          ..style = PaintingStyle.stroke
          ..strokeWidth = 2 + pulse * 2
          ..color = _gold.withOpacity(
            0.10 + pulse * 0.18,
          )
          ..maskFilter = const MaskFilter.blur(
            BlurStyle.normal,
            7,
          ),
      );
    }""",
        1,
    )

    main, version_count = re.subn(
        r"Bilgi Rotası • Sürüm 1\.25(?:\.1)?",
        "Bilgi Rotası • Sürüm 1.26",
        main,
        count=1,
    )

    if version_count != 1:
        raise RuntimeError(
            "Ana menü sürüm yazısı güncellenemedi."
        )

    pubspec = re.sub(
        r"^version:\s*.*$",
        f"version: {new_version}",
        pubspec,
        count=1,
        flags=re.MULTILINE,
    )

    MAIN.write_text(main, encoding="utf-8")
    PUBSPEC.write_text(pubspec, encoding="utf-8")

    checks = {
        MAIN: [
            "part 'visual_collection.dart';",
            "VisualCollectionService.initialize",
            "VisualCollectionService.sound",
            "const CollectionHomeButton()",
            "child: LiveBoardLayer()",
            "BoardThemeDefinition get _theme",
            "Bilgi Rotası • Sürüm 1.26",
        ],
        TARGET: [
            "class VisualCollectionService",
            "class CollectionScreen",
            "class LiveBoardLayer",
            "Antik Mısır",
            "Uzay İstasyonu",
            "Gelecek Şehri",
            "Piyon koleksiyonu",
            "Ses atmosferi",
        ],
        PUBSPEC: [f"version: {new_version}"],
    }

    for path, markers in checks.items():
        text = path.read_text(encoding="utf-8")

        for marker in markers:
            if marker not in text:
                raise RuntimeError(
                    f"Kurulum doğrulaması başarısız: "
                    f"{path} / {marker}"
                )

    if shutil.which("dart"):
        run([
            "dart",
            "format",
            "lib/main.dart",
            "lib/visual_collection.dart",
        ])

    run(["git", "diff", "--check"])

    if shutil.which("flutter"):
        run([
            "flutter",
            "analyze",
            "--no-fatal-infos",
        ])

    run([
        "git",
        "add",
        "lib/main.dart",
        "lib/visual_collection.dart",
        "pubspec.yaml",
    ])

    changed = subprocess.run(
        ["git", "diff", "--cached", "--quiet"],
        check=False,
    ).returncode != 0

    if not changed:
        raise RuntimeError(
            "Commit edilecek değişiklik bulunamadı."
        )

    run([
        "git",
        "commit",
        "-m",
        "Tahta temalari piyon koleksiyonu ve ses atmosferleri",
    ])
    committed = True

    run(["git", "push", "origin", "main"])

except Exception as error:
    if not committed:
        shutil.copy2(
            backup_dir / "main.dart",
            MAIN,
        )
        shutil.copy2(
            backup_dir / "pubspec.yaml",
            PUBSPEC,
        )

        if TARGET.exists():
            TARGET.unlink()

        subprocess.run(
            [
                "git",
                "reset",
                "--",
                "lib/main.dart",
                "lib/visual_collection.dart",
                "pubspec.yaml",
            ],
            check=False,
        )

    print("")
    print("❌ Kurulum tamamlanamadı.")
    print(str(error))

    if committed:
        print(
            "Commit oluşturuldu fakat push başarısız oldu. "
            "Tekrar dene: git push origin main"
        )
    else:
        print(
            "Dosyalar önceki hâline otomatik döndürüldü."
        )

    raise SystemExit(1)

finally:
    shutil.rmtree(backup_dir, ignore_errors=True)

print("")
print("✅ Altı tahta teması ve seviye kilitleri eklendi.")
print("✅ Mevcut 12 piyon koleksiyon ekranına taşındı.")
print("✅ Favori piyon Serbest Rota varsayılanı oldu.")
print("✅ Klasik, Sakin ve Enerjik ses atmosferleri eklendi.")
print("✅ Canlı tahta parıltısı ve aç/kapat seçeneği eklendi.")
print("✅ Ana ekrana Koleksiyon düğmesi eklendi.")
print("✅ questions.json dosyasına dokunulmadı.")
print(f"✅ Yeni sürüm: {new_version}")
print("✅ Değişiklikler GitHub main dalına gönderildi.")
